/**
 * lib/seedDemo.ts — DEMO DATA ONLY.
 *
 * ⚠️  None of the data produced by this module represents real
 * financial records. Every number is generated by a deterministic
 * seeded random walk + a few hand-tuned spikes. This module is the
 * single source of demo data for the WalletSync frontend; running it
 * never touches a real wallet, a real account, or a real customer.
 *
 * Used by:
 *   - scripts/seed-demo-data.mjs (CLI)
 *   - POST /api/persona/switch (in-app dropdown)
 *
 * Both call into the same `seedDemo(persona, days, db)` so the shape and
 * values are identical regardless of which path produced the data.
 *
 * Personas: freelancer | small_business | student
 *   See PERSONAS below for the per-persona baseline, volatility,
 *   drift, and spike cadence.
 *
 * Phase 4: writes to the v2 schema (personas + provider_balance +
 * per-persona balance_entries + meta). The caller hands us an open
 * `Database` so the migration runner in `lib/infrastructure/migrate.ts`
 * has already provisioned the schema; we only write rows.
 */

import path from "node:path";
import fs from "node:fs";
import Database from "better-sqlite3";

import { migrate } from "@/lib/infrastructure/migrate";
import { PROVIDERS, type Provider } from "@/features/wallet/types";
import { bdtToPaise } from "@/lib/domain/money";

type DB = InstanceType<typeof Database>;

const MIGRATIONS_DIR = path.resolve(
  process.cwd(),
  "src",
  "lib",
  "infrastructure",
  "migrations",
);

/* ─── public types ─────────────────────────────────────────────────── */

import type { PersonaDisplay, PersonaName } from "./metaTypes";
export type { PersonaName, MetaSnapshot } from "./metaTypes";

export interface PersonaSpec {
  name: PersonaName;
  label: string;
  description: string;
  baseline: Record<Provider, number>;
  /** Per-day random jitter (+/-), in the account's currency. */
  volatility: Record<Provider, number>;
  /** Per-day drift toward cash-out (negative) or cash-in (positive). */
  drift: Record<Provider, number>;
  /** Probability that any given day is a "payday" / large inflow day. */
  spikeChance: number;
  spikeRange: [number, number];
  /** Which providers receive the spike bump on a payday day. */
  spikeProviders: Provider[];
  /** Per-provider currency. Defaults to 'BDT' when absent. */
  currency?: Partial<Record<Provider, 'BDT' | 'USD'>>;
  /** USD→BDT exchange rate used for USD entries. Ignored for BDT. */
  usdExchangeRate?: number;
}

export interface SeedResult {
  persona: PersonaName;
  label: string;
  description: string;
  generatedAt: string;
  totalEntries: number;
  daysCovered: number;
  perProvider: Record<Provider, number>;
  dbPath: string;
}

